module RefModule(  
    input clk,  
    input load,  
    input [3:0] data_in,  
    output reg [3:0] data_out  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin  
        if (load) begin  
            data_out <= data_in;  
        end  
        // No need to specify else case, it retains current value  
    end  
endmodule
